mapper.select:
SELECT rqst_no AS rqstNo, title, cont, rqst_id AS rqstId, ins_dt AS insDt, upt_dt AS uptDt, views, group_no AS groupNo, parent_no AS parentNo, depth, order_no AS orderNo, secret, password, board_type AS boardType FROM board WHERE board_type = 'COMMUNITY_GROUP_A1'
AND (title LIKE CONCAT('%', #{keyword}, '%') OR cont LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY ins_dt DESC LIMIT #{limit} OFFSET #{offset}
